mapper.select:
SELECT r.id, r.user_id, r.question_id, r.first_mistake_time, r.last_mistake_time,
       r.mistake_count, r.status, r.mastered_time, r.created_at, r.updated_at,
       q.title AS question_title, q.category, q.difficulty
FROM mistake_record r
INNER JOIN question q ON r.question_id = q.id AND q.is_deleted = 0
WHERE r.user_id = #{userId}

    AND q.category = #{category}


    AND q.difficulty = #{difficulty}


    AND r.status = #{status}


    AND (q.title LIKE CONCAT('%', #{keyword}, '%') OR q.content LIKE CONCAT('%', #{keyword}, '%'))

ORDER BY r.last_mistake_time DESC
LIMIT #{offset}, #{size}

SELECT COUNT(*)
FROM mistake_record r
INNER JOIN question q ON r.question_id = q.id AND q.is_deleted = 0
WHERE r.user_id = #{userId}

    AND q.category = #{category}


    AND q.difficulty = #{difficulty}


    AND r.status = #{status}


    AND (q.title LIKE CONCAT('%', #{keyword}, '%') OR q.content LIKE CONCAT('%', #{keyword}, '%'))

mapper.update:
UPDATE mistake_record
SET status = #{status},
    mastered_time = #{masteredTime}
WHERE id = #{id}

UPDATE mistake_record
SET last_mistake_time = #{time}
WHERE id = #{id}

mapper.select:
SELECT r.id AS mistakeRecordId, r.question_id AS id, q.title, q.content, q.answer,
       q.difficulty, q.category, r.mistake_count AS mistakeCount
FROM mistake_record r
INNER JOIN question q ON r.question_id = q.id AND q.is_deleted = 0
WHERE r.user_id = #{userId}
  AND r.status = 0

    AND q.category = #{category}


    AND q.difficulty = #{difficulty}

ORDER BY r.last_mistake_time DESC
LIMIT #{count}

SELECT COUNT(*)
FROM mistake_record r
INNER JOIN question q ON r.question_id = q.id AND q.is_deleted = 0
WHERE r.user_id = #{userId}
  AND r.status = 0

    AND q.category = #{category}


    AND q.difficulty = #{difficulty}
